<div class="xpro-device-slider-wrapper">
	<div class="xpro-device-slider-inner xpro-device-slider-<?php echo esc_attr( $device_type ); ?>">
		<?php
		if ( $settings['device_type'] ) :
			echo $svg;
		endif;
		?>
		<div id="xpro-device-slider-<?php echo esc_attr( $this->get_id() ); ?>" class="xpro-device-slider owl-carousel xpro-owl-theme xpro-owl-navigation-horizontal-<?php echo esc_attr( $settings['nav_layout'] ?? 'style-1' ); ?> xpro-owl-dots-horizontal-<?php echo esc_attr( $settings['dots_layout'] ?? 'style-1' ); ?>">
			<?php foreach ( $settings['item'] as $i => $item ) : ?>
				<div class="xpro-device-slider-item">
					<?php if ( 'image' === $item['background'] ) : ?>
						<?php
						if ( 'image' === $item['background'] ) {
							echo wp_kses_post( Group_Control_Image_Size::get_attachment_image_html( $item, 'media_thumbnail', 'image' ) );
						}
						?>
					<?php endif; ?>

					<?php if ( 'video' === $item['background'] && $item['video_link'] ) : ?>
						<video autoplay muted loop playsinline>
							<source src="<?php echo esc_url( $item['video_link'] ); ?>">
						</video>
					<?php endif; ?>

					<?php if ( 'hosted' === $item['background'] && $item['hosted_url']['url'] ) : ?>
						<video autoplay muted loop playsinline>
							<source src="<?php echo esc_url( $item['hosted_url']['url'] ); ?>">
						</video>
					<?php endif; ?>

					<?php
					if ( 'youtube' === $item['background'] && $item['youtube_link'] ) :
						$media_id = ( preg_match( '%(?:youtube(?:-nocookie)?\.com/(?:[^/]+/.+/|(?:v|e(?:mbed)?)/|.*[?&]v=)|youtu\.be/)([^"&?/ ]{11})%i', $item['youtube_link'], $match ) ) ? $match[1] : false;
						$url      = '//www.youtube.com/embed/' . $media_id . '?autoplay=1&mute=1&amp;controls=0&amp;showinfo=0&amp;rel=0&amp;loop=1&amp;modestbranding=1&amp;wmode=transparent&amp;playsinline=1&playlist=' . $media_id;
						?>
						<iframe src="<?php echo esc_url( $url ); ?>" allowfullscreen="allowfullscreen"></iframe>
					<?php endif; ?>
				</div>
			<?php endforeach; ?>
		</div>
	</div>
</div>

